usage.basic:
const { HttpClientWithRetry } = require('http-retry-circuit-breaker');
const client = new HttpClientWithRetry({ maxRetries: 3 });
const response = await client.get('https://api.example.com/data');

usage.advanced:
const client = new HttpClientWithRetry({
  maxRetries: 5,
  baseDelay: 500,
  maxDelay: 30000,
  circuitBreaker: {
    failureThreshold: 10,
    resetTimeout: 60000
  }
});
